package com.hospital.management.validation;
import com.hospital.management.model.PatientForm;import java.time.*;import java.util.Set;import java.util.regex.Pattern;
/** Server-side validation for patient forms. */
public class PatientValidator{private static final Pattern NUM=Pattern.compile("[A-Z0-9-]{3,30}"),USER=Pattern.compile("[A-Za-z][A-Za-z0-9._-]{3,49}"),EMAIL=Pattern.compile("^[^\\s@]+@[^\\s@]+\\.[^\\s@]+$"),PHONE=Pattern.compile("\\+?[0-9][0-9 ()-]{6,19}");private static final Set<String> GENDERS=Set.of("MALE","FEMALE","OTHER"),BLOOD=Set.of("A+","A-","B+","B-","AB+","AB-","O+","O-","UNKNOWN"),STATUS=Set.of("ACTIVE","INACTIVE");
 public ValidationResult validateCreate(PatientForm f){return validate(f,true,f.isCreateLoginAccount());}public ValidationResult validateEdit(PatientForm f,boolean linked){return validate(f,false,linked||f.isCreateLoginAccount());}private ValidationResult validate(PatientForm f,boolean create,boolean login){ValidationResult r=new ValidationResult();if(!blank(f.getPatientNumber())&&!NUM.matcher(f.getPatientNumber()).matches())r.addError("patientNumber","Use 3-30 uppercase letters, digits or hyphens");text(r,"firstName",f.getFirstName(),2,100,true);text(r,"lastName",f.getLastName(),1,100,true);try{LocalDate d=LocalDate.parse(f.getDateOfBirth());if(d.isAfter(LocalDate.now())||d.isBefore(LocalDate.of(1900,1,1)))throw new Exception();}catch(Exception e){r.addError("dateOfBirth","Enter a valid date from 1900 through today");}if(!GENDERS.contains(f.getGender()))r.addError("gender","Select a valid gender");if(!BLOOD.contains(f.getBloodGroup()))r.addError("bloodGroup","Select a valid blood group");phone(r,"phone",f.getPhone(),true);if(!blank(f.getEmail())&&(f.getEmail().length()>150||!EMAIL.matcher(f.getEmail()).matches()))r.addError("email","Enter a valid email address");text(r,"address",f.getAddress(),0,500,false);text(r,"emergencyContactName",f.getEmergencyContactName(),0,150,false);phone(r,"emergencyContactPhone",f.getEmergencyContactPhone(),false);if(!STATUS.contains(f.getStatus()))r.addError("status","Status must be ACTIVE or INACTIVE");if(login){if(f.getUsername()==null||!USER.matcher(f.getUsername()).matches())r.addError("username","Username must start with a letter and contain 4-50 permitted characters");if(blank(f.getEmail()))r.addError("email","Email is required for a login account");String p=f.getPassword();if(create||f.isCreateLoginAccount()||!blank(p)){if(p==null||p.length()<8||p.length()>72||!p.matches(".*[A-Z].*")||!p.matches(".*[a-z].*")||!p.matches(".*\\d.*")||!p.matches(".*[^A-Za-z0-9].*"))r.addError("password","Password must be 8-72 characters with upper, lower, digit and special characters");else if(!p.equals(f.getConfirmPassword()))r.addError("confirmPassword","Passwords do not match");}}return r;}private void text(ValidationResult r,String k,String v,int min,int max,boolean req){int n=v==null?0:v.trim().length();if((req&&n<min)||n>max)r.addError(k,"Enter a valid "+k);}private void phone(ValidationResult r,String k,String v,boolean req){if((req||!blank(v))&&(v==null||!PHONE.matcher(v).matches()))r.addError(k,"Enter a valid phone number");}private boolean blank(String s){return s==null||s.isBlank();}}
